import React, { useEffect, useRef, useState } from "react";

// Animation states
const IDLE = "idle";
const BOWLING = "bowling";
const BATTING = "batting";
const RESULT_SHOW = "result_show";

function Pitch({ result, animPhase, commentary }) {
  // Ball position: starts at bowler side (left ~10%), moves to batsman (right ~75%)
  const [ballX, setBallX] = useState(12); // percent
  const [ballVisible, setBallVisible] = useState(true);
  const [batSwing, setBatSwing] = useState(false);
  const [showResult, setShowResult] = useState(false);
  const animRef = useRef(null);
  const prevPhase = useRef(IDLE);

  useEffect(() => {
    if (animPhase === prevPhase.current) return;
    prevPhase.current = animPhase;

    if (animRef.current) clearInterval(animRef.current);
    setBatSwing(false);
    setShowResult(false);

    if (animPhase === BOWLING) {
      // Ball travels from bowler to batsman
      setBallVisible(true);
      setBallX(12);
      let x = 12;
      animRef.current = setInterval(() => {
        x += 2.2;
        setBallX(x);
        if (x >= 72) {
          clearInterval(animRef.current);
        }
      }, 18);
    }

    if (animPhase === BATTING) {
      // Trigger bat swing
      setBatSwing(true);
      // If wicket, ball stays; if runs, ball flies off
      if (result && result !== "W") {
        setTimeout(() => {
          let x = 72;
          animRef.current = setInterval(() => {
            x -= 3;
            setBallX(x);
            if (x <= -5) {
              clearInterval(animRef.current);
              setBallVisible(false);
            }
          }, 18);
        }, 120);
      }
      setTimeout(() => {
        setBatSwing(false);
        setShowResult(true);
      }, 500);
    }

    if (animPhase === IDLE) {
      setBallX(12);
      setBallVisible(true);
      setBatSwing(false);
      setShowResult(false);
    }

    return () => clearInterval(animRef.current);
  }, [animPhase, result]);

  const resultColor = () => {
    if (!result) return "#fff";
    if (result === "W") return "#ff4444";
    if (result === "6") return "#FFD700";
    if (result === "4") return "#00e676";
    return "#90caf9";
  };

  const resultLabel = () => {
    if (!result) return "";
    if (result === "W") return "WICKET! 🏏";
    if (result === "6") return "SIX! 🎉";
    if (result === "4") return "FOUR! 🏃";
    if (result === "0") return "DOT BALL";
    return `${result} RUN${result === "1" ? "" : "S"}`;
  };

  return (
    <div className="pitch-wrapper">
      {/* Cricket field SVG */}
      <svg
        className="pitch-svg"
        viewBox="0 0 700 260"
        xmlns="http://www.w3.org/2000/svg"
      >
        {/* Outfield */}
        <ellipse cx="350" cy="130" rx="340" ry="125" fill="#2e7d32" />
        {/* Inner circle */}
        <ellipse cx="350" cy="130" rx="200" ry="90" fill="#388e3c" stroke="#a5d6a7" strokeWidth="1.5" strokeDasharray="8 5" />
        {/* Pitch strip */}
        <rect x="130" y="108" width="430" height="44" rx="4" fill="#c8b87a" stroke="#a08040" strokeWidth="1.5" />
        {/* Crease lines */}
        <line x1="175" y1="108" x2="175" y2="152" stroke="white" strokeWidth="2" />
        <line x1="175" y1="108" x2="200" y2="108" stroke="white" strokeWidth="2" />
        <line x1="175" y1="152" x2="200" y2="152" stroke="white" strokeWidth="2" />
        <line x1="520" y1="108" x2="520" y2="152" stroke="white" strokeWidth="2" />
        <line x1="520" y1="108" x2="495" y2="108" stroke="white" strokeWidth="2" />
        <line x1="520" y1="152" x2="495" y2="152" stroke="white" strokeWidth="2" />
        {/* Stumps - bowler end */}
        <rect x="170" y="106" width="3" height="20" fill="#f5deb3" />
        <rect x="176" y="106" width="3" height="20" fill="#f5deb3" />
        <rect x="182" y="106" width="3" height="20" fill="#f5deb3" />
        {/* Bails bowler */}
        <rect x="169" y="105" width="18" height="2" rx="1" fill="#e8d5b0" />
        {/* Stumps - batsman end */}
        <rect x="515" y="106" width="3" height="20" fill="#f5deb3" />
        <rect x="521" y="106" width="3" height="20" fill="#f5deb3" />
        <rect x="527" y="106" width="3" height="20" fill="#f5deb3" />
        {/* Bails batsman */}
        <rect x="514" y="105" width="18" height="2" rx="1" fill="#e8d5b0" />

        {/* Bowler figure */}
        <g transform="translate(155, 90)">
          {/* Body */}
          <rect x="0" y="18" width="12" height="22" rx="3" fill="#1565c0" />
          {/* Head */}
          <circle cx="6" cy="12" r="9" fill="#ffccbc" />
          {/* Cap */}
          <ellipse cx="6" cy="5" rx="9" ry="4" fill="#0d47a1" />
          {/* Legs */}
          <rect x="0" y="38" width="5" height="16" rx="2" fill="#1565c0" />
          <rect x="7" y="38" width="5" height="16" rx="2" fill="#1565c0" />
          {/* Bowling arm */}
          <line x1="12" y1="22" x2="22" y2="15" stroke="#ffccbc" strokeWidth="3" strokeLinecap="round" />
        </g>

        {/* Batsman figure */}
        <g transform="translate(490, 88)">
          {/* Body */}
          <rect x="0" y="18" width="14" height="24" rx="3" fill="#b71c1c" />
          {/* Head */}
          <circle cx="7" cy="12" r="9" fill="#ffccbc" />
          {/* Helmet */}
          <path d="M-2 10 Q7 0 16 10" fill="#b71c1c" />
          <rect x="-2" y="10" width="18" height="5" rx="2" fill="#b71c1c" />
          {/* Pads */}
          <rect x="0" y="40" width="6" height="18" rx="3" fill="#f5f5f5" />
          <rect x="8" y="40" width="6" height="18" rx="3" fill="#f5f5f5" />
          {/* BAT */}
          <g
            style={{
              transformOrigin: "7px 22px",
              transform: batSwing ? "rotate(-60deg)" : "rotate(20deg)",
              transition: "transform 0.15s ease-out",
            }}
          >
            <rect x="14" y="14" width="5" height="30" rx="2" fill="#e8c87a" />
            <rect x="15" y="14" width="3" height="8" rx="1" fill="#c8a050" />
          </g>
        </g>

        {/* Cricket Ball */}
        {ballVisible && (
          <g
            style={{
              transform: `translateX(${ballX * 7}px) translateY(0px)`,
              transition: "none",
            }}
          >
            <circle cx="0" cy="130" r="9" fill="#cc2200" />
            <line x1="-4" y1="127" x2="4" y2="133" stroke="#fff" strokeWidth="1" opacity="0.6" />
          </g>
        )}
      </svg>

      {/* Result overlay */}
      {showResult && result && (
        <div
          className="result-overlay"
          style={{ color: resultColor() }}
        >
          {resultLabel()}
        </div>
      )}

      {/* Commentary */}
      {showResult && commentary && (
        <div className="commentary">{commentary}</div>
      )}
    </div>
  );
}

export { IDLE, BOWLING, BATTING, RESULT_SHOW };
export default Pitch;
